export default function  Detail (props)  {
    const {state,dispatch} = useWeb3();
    const { maincontract,web3Instance,Account} = state;

    const [detail, setDetail] = useState(null);
    const { closeBox, detailId, openModal } = props;

    useEffect(() => {

        if( maincontract==null || web3Instance == null) return;

        const getServiceById = async () =>{
            dispatch({type: 'SET_LOADING',payload:{
                    tips:"Get Services By Id",
                }});
            services.getServiceById(maincontract,detailId).then((data)=>{
                dispatch({type: 'SET_LOADING',payload:null});
                setDetail(data)
            })
        }
        getServiceById()
    }, [dispatch,maincontract,web3Instance,detailId]);

    const switchTime = (dateTime) =>{
        const daytime = parseInt(dateTime) * 1000;
        return new Date(daytime).toLocaleString();
    }

    const switchEndTime = (dateTime,grace) =>{
        const times = parseInt(dateTime) + parseInt(grace);
        return switchTime(times);
    }

    const toThousands = (str) => {
        let balance = web3Instance.web3Instance.utils.fromWei(str);
        return  PublicObj.ToThousands(balance);
    }

    if(detail == null) return <div />;
    const { spname, logo, name, desc, share, created, period, totalReward, totalStake, threshold,id,grace,status } = detail;
    return (
        <Bg>
            {
                detail != null &&   <BgLayer>
                    <FirstRow>
                        <LftT>
                            <ImgRadius src={logo} alt=""/>
                            <Author>by {spname}</Author>
                        </LftT>
                    </FirstRow>
                    <div>
                        <Titles>{name}</Titles>
                        <ContentS>{desc}</ContentS>
                        <Ul>
                            <Li>
                                <Star>*</Star>
                                <Names>Target</Names>
                                <PercentS>{toThousands(threshold)}APN</PercentS>
                            </Li>
                            <Li>
                                <Star>*</Star>
                                <Names>Share</Names>
                                <PercentS>{share}%</PercentS>
                            </Li>
                            <Li>
                                <Star>*</Star>
                                <Names>Estimate Apy</Names>
                                <PercentS>{PublicObj.handleApy(totalReward, totalStake, period)}%</PercentS>
                            </Li>
                        </Ul>
                        <Times>
                            <div>
                                <TimeTitle>start</TimeTitle>
                                <TimeNum>{switchTime(created)}</TimeNum>
                            </div>
                            <img src={Arrow} alt=""/>
                            <div>
                                <TimeTitle>ending</TimeTitle>
                                <TimeNum>{switchEndTime(created,grace)}</TimeNum>
                            </div>
                        </Times>
                        <div>
                            <PercentBg>
                                <Active style={{width: PublicObj.handleWidth(totalStake,threshold) + '%'}} />
                            </PercentBg>
                            <Texts>{toThousands(totalStake)}  / {toThousands(threshold)}  APN</Texts>
                        </div>
                    </div>
                    <LastRow>
                        <BtnClose onClick={()=>closeBox()}>close</BtnClose>
                        <Btn onClick={()=>openModal(id,name)}  disabled={ status !== '0' || Account == null}>stake</Btn>
                    </LastRow>
                </BgLayer>
            }

        </Bg>
    );

}
